+    _ = loader; // For now, just do simple dequantization without GGUF metadata
+
+    // Q8_0 format: blocks of [f16 delta][32 x i8]
+    const Q8_BLOCK_SIZE = 32;
+    const Q8_BLOCK_BYTES = 34; // 2 (f16) + 32 (i8)
+
+    const n_blocks = quantized_data.len / Q8_BLOCK_BYTES;
+    const n_elements = n_blocks * Q8_BLOCK_SIZE;
+
+    if (n_elements != expected_size) {
+        std.debug.print("Warning: size mismatch {} != {}\n", .{n_elements, expected_size});
+    }
+
+    var result = try allocator.alloc(f32, expected_size);
+
+    var block_idx: usize = 0;
+    while (block_idx < n_blocks) : (block_idx += 1) {
+        const block_offset = block_idx * Q8_BLOCK_BYTES;
+        const out_offset = block_idx * Q8_BLOCK_SIZE;
+
+        // Read delta (f16 -> f32)
+        const delta_bits = std.mem.readInt(u16, quantized_data[block_offset..][0..2], .little);
+        const delta = f16ToF32(delta_bits);
+
+        // Dequantize 32 values
+        for (0..Q8_BLOCK_SIZE) |i| {
+            const quant_val = @as(i8, @bitCast(quantized_data[block_offset + 2 + i]));
+            if (out_offset + i < expected_size) {
+                result[out_offset + i] = delta * @as(f32, @floatFromInt(quant_val));
+            }
+        }
+    }
+
+    return result;
+}
+
+/// Convert F16 to F32
+inline fn f16ToF32(bits: u16) f32 {
+    const sign: u32 = @as(u32, bits >> 15) << 31;
+    const exp: u32 = (bits >> 10) & 0x1F;
+    const mant: u32 = bits & 0x3FF;
+
+    if (exp == 0) {
+        if (mant == 0) return @bitCast(sign);
+        // Denormal
+        var m = mant;
+        var e: i32 = -14;
+        while ((m & 0x400) == 0) {
+            m <<= 1;
+            e -= 1;
+        }
+        m &= 0x3FF;
+        const exp32: u32 = @intCast(e + 127);
+        return @bitCast(sign | (exp32 << 23) | (m << 13));
+    } else if (exp == 31) {
+        if (mant == 0) return @bitCast(sign | 0x7F800000);
+        return @bitCast(sign | 0x7FC00000 | (mant << 13));
+    }
+
+    const exp32: u32 = exp + 127 - 15;
+    return @bitCast(sign | (exp32 << 23) | (mant << 13));
 }
